import React, { useState, useEffect } from 'react';
import { Calendar, Plus, Globe, RefreshCw, Flag } from 'lucide-react';

const NationalHolidays = ({ onAddHoliday, API_BASE_URL, token }) => {
  const [nationalHolidays, setNationalHolidays] = useState([]);
  const [loading, setLoading] = useState(false);
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());

  const years = Array.from({ length: 5 }, (_, i) => new Date().getFullYear() + i);

  const fetchOfficialIndianHolidays = async () => {
    setLoading(true);
    try {
      // Using your backend API for official Indian holidays
      const response = await fetch(
        `${API_BASE_URL}/holidays/official?year=${selectedYear}`,
        {
          headers: {
            'Authorization': `Bearer ${token}`
          }
        }
      );

      if (response.ok) {
        const holidays = await response.json();
        setNationalHolidays(holidays);
      } else {
        // Fallback to mock data if API fails
        setNationalHolidays(getMockIndianHolidays());
      }
    } catch (error) {
      console.log('Using mock data due to API error:', error);
      setNationalHolidays(getMockIndianHolidays());
    } finally {
      setLoading(false);
    }
  };

  // No hardcoded data - only API calls

  const handleAddHoliday = (holiday) => {
    const holidayData = {
      name: holiday.name,
      date: holiday.date,
      type: 'national',
      country: 'IN'
    };

    onAddHoliday(holidayData);
  };

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    return date.toLocaleDateString('en-IN', {
      weekday: 'long',
      year: 'numeric',
      month: 'long',
      day: 'numeric'
    });
  };

  useEffect(() => {
    fetchOfficialIndianHolidays();
  }, [selectedYear, API_BASE_URL, token]);

  return (
    <div className="bg-white rounded-lg shadow p-6">
      <div className="flex items-center justify-between mb-6">
        <div className="flex items-center space-x-3">
          <div className="p-2 bg-orange-100 rounded-lg">
            <Flag className="w-5 h-5 text-orange-600" />
          </div>
          <h3 className="text-lg font-semibold text-gray-900">Official Indian Holidays</h3>
        </div>
        <button
          onClick={fetchOfficialIndianHolidays}
          disabled={loading}
          className="flex items-center space-x-2 px-3 py-2 text-sm font-medium text-orange-600 hover:text-orange-700 hover:bg-orange-50 rounded-lg transition-all duration-200"
        >
          <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
          <span>Refresh</span>
        </button>
      </div>

      {/* Year Selection */}
      <div className="mb-6">
        <label className="block text-sm font-medium text-gray-700 mb-2">Select Year</label>
        <select
          value={selectedYear}
          onChange={(e) => setSelectedYear(parseInt(e.target.value))}
          className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500 focus:border-orange-500"
        >
          {years.map(year => (
            <option key={year} value={year}>{year}</option>
          ))}
        </select>
      </div>

      {/* Holidays List */}
      <div className="space-y-3">
        {loading ? (
          <div className="text-center py-8">
            <RefreshCw className="w-8 h-8 text-orange-600 animate-spin mx-auto mb-2" />
            <p className="text-gray-600">Loading official holidays...</p>
          </div>
        ) : nationalHolidays.length > 0 ? (
          nationalHolidays.map((holiday, index) => (
            <div key={index} className="flex items-center justify-between p-4 bg-orange-50 rounded-lg border border-orange-200">
              <div className="flex-1">
                <h4 className="font-medium text-gray-900">{holiday.name}</h4>
                <p className="text-sm text-gray-600">{formatDate(holiday.date)}</p>
                <div className="flex items-center space-x-2 mt-1">
                  <span className="inline-flex items-center px-2 py-1 rounded-full text-xs font-medium bg-orange-100 text-orange-800">
                    Official Holiday
                  </span>
                  <span className="inline-flex items-center px-2 py-1 rounded-full text-xs font-medium bg-blue-100 text-blue-800">
                    India
                  </span>
                </div>
              </div>

              <button
                onClick={() => handleAddHoliday(holiday)}
                className="flex items-center space-x-2 px-3 py-2 text-sm font-medium text-orange-600 hover:text-orange-700 hover:bg-orange-100 rounded-lg transition-all duration-200 border border-orange-200 hover:border-orange-300"
              >
                <Plus className="w-4 h-4" />
                <span>Add</span>
              </button>
            </div>
          ))
        ) : (
          <div className="text-center py-8 text-gray-600">
            <Flag className="w-12 h-12 text-gray-400 mx-auto mb-2" />
            <p>No official holidays found for {selectedYear}.</p>
          </div>
        )}
      </div>

      <div className="mt-6 p-4 bg-orange-50 rounded-lg border border-orange-200">
        <p className="text-sm text-orange-800">
          <strong>Info:</strong> These are official Indian national holidays. Click "Add" to include them in your personal calendar. 
          You can then manage these holidays in the Holiday Management section below.
        </p>
      </div>
    </div>
  );
};

export default NationalHolidays;
